module Acme.Billing (charge) where

import Network.HTTP.Simple (Request, addRequestHeader)
import Data.ByteString.Char8 (pack)
import System.Environment (getEnv)

charge :: Request -> IO Request
charge req = do
  token <- getEnv "BILLING_API_TOKEN"
  pure (addRequestHeader "Authorization" (pack ("Bearer " <> token)) req)
